SELECT AVG(square_footage) AS average_square_footage
FROM properties
WHERE city = 'Los Angeles' AND status = 'available';

SELECT feature_name
FROM property_features
WHERE feature_type = 'amenity';

SELECT address 
FROM properties 
ORDER BY address;

SELECT AVG(rating) AS average_tenant_rating
FROM property_reviews
WHERE review_type = 'tenant' AND review_status = 'approved';

SELECT COUNT(*) AS available_property_count
FROM properties
WHERE status = 'available' AND city = 'New York';
